import{_ as a,o as b,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"圣战天使","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/圣战天使.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/圣战天使.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/圣战天使.md"};function o(d,e,l,_,i,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"圣战天使",tabindex:"-1"},[p("圣战天使 "),r("a",{class:"header-anchor",href:"#圣战天使","aria-label":'Permalink to "圣战天使"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),n('<h1 id="圣战天使-1" tabindex="-1">圣战天使 <a class="header-anchor" href="#圣战天使-1" aria-label="Permalink to &quot;圣战天使&quot;">​</a></h1><p>圣战天使<br> C+1250<br> 特殊的人类，能够进行「同契」、将自己的肉体变为武器的种族。武器化的圣战天使外形、特殊能力多种多样，一般的枪炮火器无法被认为是无法与武器化的圣战天使对抗的。因为武器化的关系，圣战天使消耗的力量依靠一般的方法比如饮食睡眠或者休息时无法回复的，必须依靠特殊的方式才能回复力量（当然，依靠睡眠或者饮食来回复力量的圣战天使也是存在的）。</p><p>购买时需选择天使属性：地/水/风/火<br> 本体为14~22岁的人类女性，无任何特殊能力，外表可自设，相貌最低为3。</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量1<br> ■敏捷1<br> ■耐力1<br> ▓▓心智属性<br> ■智力1<br> ■感知1<br> ■决心3<br> ▓▓互动属性<br> ■风度5<br> ■操控1<br> ■沉着1</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动1<br> ■求生1<br> ■射击1<br> ■武技1</p><p>▓▓心智系<br> ■学识1<br> ■器用3 驾驶3<br> ■手艺1<br> ■专注1</p><p>▓▓互动系<br> ■洞察1<br> ■隐秘1<br> ■表达1<br> ■社交1 交际1</p><p>▓▓▓▓衍生属性值<br> ▓体积 4<br> ▓速度 （力量【1】+敏捷【1】+体积【4】+每1点敏捷上的附加获得3移动速度）=6米<br> ▓先攻 （敏捷【1】+沉着【1】）=2<br> ▓防御 （敏捷感知的平均值【1】+较高者的附加成功【】）= 1<br> ▓生命值 （耐力【1】+体积【4】+耐力附加【 】×5）=5<br> ▓意志力池 （决心【3】+沉着【1】+决心附加【 】×2）=4<br> ▓意志 （决心【3】+专注1+意志【0】）=4<br> ▓反射 （敏捷【1】+运动1+反射【0】）=2<br> ▓强韧 （耐力【1】+生存1+强韧【0】）=2<br> ▓侦查 （感知【1】+洞察1+侦查【0】）=2<br> ▓敏感范围 （感知【1】*20米+感知上的附加成功【0】*20米）=20米</p><p>可通过契约者切换为武器形态，切换形态是一个移动动作：<br> 圣战天使-刀型<br> 分类：大刀/武士刀/马刀<br> 武器伤害；伤害11L/12L<br> 武器特性：破甲1/ 高速1<br> 武器体积：3/4</p><p>【能量充盈】使用圣战天使以一个迅捷动作使能量充盈刀身，下次攻击命中后造成等同于持有者传奇决心*2点额外的严重伤害，伤害类型根据天使属性（火：火焰，水：冻寒，风：音波，地：钝击）进行转化。</p><p>【天使的提醒】圣战天使的提醒在耳畔环绕，使你获得1点闪避防御，以及在先攻上的2点数值提升。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
